	for (int i = 0;i < n; i++) {
		b[i] = d;
		d++;
	}
	for (int j = 0; j < m; j++) {
		int k = timGiaTri(b, a, n, m, j);
		doiGiaTri(k, b);
		b[0] = a[j]; 
		}
	cout << "Disk stack: ";
	for (int i = 0; i < n; i++) {
		cout << b[i] << " ";
	}
	return 0;
}

