void rearrangeDisks(int disks[], int numDisks, int changes[], int numChanges) {
    for (int i = 0; i < numChanges; i++) {
        int diskToMove = changes[i];

        int diskPosition = -1;
        for (int j = 0; j < numDisks; j++) {
            if (disks[j] == diskToMove) {
                diskPosition = j;
                break;
            }
        }

        for (int j = diskPosition; j > 0; j--) {
            disks[j] = disks[j - 1];
        }
        disks[0] = diskToMove;
    }
}

