#include <iostream>
const int SIZE = 100;
using namespace std;

void makeSymmerVerticalAxis(int mat[][SIZE], int row, int col)
{
    int mid;
    if (col % 2 != 0) mid = (col / 2);
    else mid = (col / 2) ;

    for (int i = 0; i < row; ++i)
    {
        int right = col - 1; //vi tri cot ben phai
        for (int j = 0; j < mid; ++j)
        {
            int temp = mat[i][j];
            mat[i][j] = mat[i][right];
            mat[i][right] = temp;
            right--;
        }
    }
}


