				}
				result[m].pokeName[strlen(pokemons[i].pokeName)] = '\0';
				m++;
			} else if (type1 != "NULL" && pokemons[i].type2 == type1){
				for (int j = 0; j < strlen(pokemons[i].pokeID); j++){
					result[m].pokeID[j] = pokemons[i].pokeID[i];
