void updateDiskStack(int diskStack[], int n, int diskNumber) {
    // Tìm vị trí của đĩa trong chồng đĩa
    auto it = find(diskStack, diskStack + n, diskNumber);

    // Di chuyển đĩa đó lên trên cùng
    rotate(diskStack, it, it + 1);
}

