	while (line[pos] != ',') poke.pokeID[write_pos++] = line[pos++];
	++pos;
	poke.pokeID[write_pos] = 0;
	write_pos = 0;
	while (line[pos] != ',') poke.pokeName[write_pos++] = line[pos++];
	++pos;
