	write_pos = 0;
	while (line[pos] != ',') poke.type2[write_pos++] = line[pos++];
	++pos;
	poke.type2[write_pos] = 0;
	poke.speed = 0;
	while (line[pos]) poke.speed = poke.speed * 10 + (line[pos++] - '0');
}

