	cout << "Input number of changes: ";
	cin >> changes;
	int b[changes];
	cout << "The order of changes: ";
	for (int i = 0; i < changes; i++) cin >> b[i];
	Execute(a, n, b, changes);
	cout << "Disk stack: ";
	print(a, n);
	return 0;
}


