    int n;
    cout << "Input: ";
    cin >> n;

    if (n < 1000 || n > 9999) {
        cout << "Error, input again. " << endl;
        return 1;
    }

    int largestPalindrome = findLargestPalindrome(n);
    cout << "Output: " << largestPalindrome << endl;

