{
	int result = -1;

	int left = n , right = 0 , pow = 1;
	while ( left != 0 ){
		int temp1 = left % 10;
		left /= 10;

		int temp2 = left*pow + right;

		///// check dung de danh dau so luong chu so can xoa
		if (check != 0)
			temp2 = delDigit(temp2 , check - 1);

		if ( checkReverse(temp2) && temp2 > result )
			result = temp2;

		right += temp1*pow;	
		pow *= 10;
	}

	return result;
}

