const int MAX_LEN = 256;

void deleteCharFrom(char s[], int pos, int numChar) {
    int len = strlen(s);
    for (int i = pos; s[i + numChar] != '\0'; i++) {
        s[i] = s[i + numChar];
    }
    s[len - numChar] = '\0';
}

void xoaKiTuTrungLap(char s[]) {
    bool xoaXong = false;
    while (!xoaXong) {
        xoaXong = true;
        for (int i = 1; s[i] != '\0'; i++) {
            if (s[i] == s[i - 1]) {
                deleteCharFrom(s, i - 1, 2);
                xoaXong = false;
            }
        }
    }
}

