        cout << "Share: ";
        cin >> teams[i].share;
        cin.ignore();  

        teams[i].score = teams[i].like + 2 * teams[i].comment + 3 * teams[i].share;

        numTeams++;
    }

    sortTeams(teams, numTeams);

    int numWinners = std::min(3, numTeams);

    for (int i = 0; i < numWinners; i++) {
