	int pos = -1, numberBest = 0;

	for (int i = 0; i < n; i++) {
		a[i].point = a[i].like + 2 * a[i].comment + 3 * a[i].share;
	}

	int max = a[0].point;

	for (int i = 0; i < n; i++) {
		if (max < a[i].point) {
			max = a[i].point;
			pos = i;
			Thebest[numberBest] = a[i];
		}
	}

	numberBest = 1;

	for (int i = 0; i < n; i++) {
		if (i == pos)
			continue;
		else {
			if (a[i].point == max) {
				Thebest[numberBest] = a[i];
				numberBest++;
			}
		}
	}

	for (int i = 0; i < numberBest; i++) {
		cout << Thebest[i].name << endl;
	}
}

