    {
        sum += Matrix[i][temp];
        temp--;
    }

    return sum;
}

int tinh_Tong_matrix (int Matrix[100][100], int n)
{
    int sum = 0;

    for (int i = 0; i < n; i++)
    {
        for (int j = 0; j < n; j++)
        {
            sum += Matrix[i][j];
        }
