        for (int j = 0; j < n; j++) {
            cin >> matrix[i][j];
        }
    }

    bool isSymmetric = isDiagonalSymmetric(matrix, n);

    if (isSymmetric) {
        cout << "Ma tran doi xung qua duong cheo chinh hoac duong cheo phu.\n";
    } else {
        cout << "Ma tran khong doi xung qua duong cheo chinh hoac duong cheo phu.\n";
